import { useEffect } from 'react';
import { useAppStore } from '@/layers/shared/model';

/**
 * Register the `Cmd+.` / `Ctrl+.` key handler that toggles the right panel.
 *
 * Replaces the previous `useCanvasShortcut` -- since the canvas has migrated
 * into the right panel, the same shortcut now controls the panel itself.
 */
export function useRightPanelShortcut(): void {
  const toggleRightPanel = useAppStore((s) => s.toggleRightPanel);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === '.') {
        e.preventDefault();
        toggleRightPanel();
      }
    };

    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [toggleRightPanel]);
}
```

Note: This uses `toggleRightPanel` from the store (which internally calls `get()` to read current state and then calls `setRightPanelOpen`). Unlike the old `useCanvasShortcut`, the toggle action is a single stable reference that doesn't need `canvasOpen` in the dependency array.

